import torch
import torchvision.transforms as transforms
import torchvision.models as models
from flask import Flask, request, jsonify
from PIL import Image
import io
import numpy as np

app = Flask(__name__)

# Load pretrained model
model = models.resnet50(pretrained=True)
model.eval()

# Load ImageNet class labels
IMAGENET_CLASSES_URL = "https://raw.githubusercontent.com/pytorch/hub/master/imagenet_classes.txt"
try:
    import urllib.request
    response = urllib.request.urlopen(IMAGENET_CLASSES_URL)
    categories = [s.strip().decode('utf-8') for s in response.readlines()]
except Exception:
    categories = [f"class_{i}" for i in range(1000)]

# Define strict preprocessing pipeline to normalize inputs and reduce adversarial effectiveness
STANDARD_TRANSFORM = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

# Adversarial defense: input transformation defenses
def apply_input_defenses(image: Image.Image) -> Image.Image:
    """
    Apply input transformation defenses to mitigate adversarial examples.
    These transformations destroy carefully crafted adversarial perturbations
    while preserving semantic content for legitimate images.
    """
    # Defense 1: JPEG compression to remove high-frequency adversarial perturbations
    jpeg_buffer = io.BytesIO()
    image.save(jpeg_buffer, format='JPEG', quality=75)
    jpeg_buffer.seek(0)
    image = Image.open(jpeg_buffer).copy()

    # Defense 2: Slight Gaussian blur to smooth adversarial noise
    from PIL import ImageFilter
    image = image.filter(ImageFilter.GaussianBlur(radius=0.5))

    # Defense 3: Bit-depth reduction (quantization) to reduce adversarial perturbation space
    img_array = np.array(image)
    depth = 4  # reduce to 4 bits per channel
    img_array = (img_array >> (8 - depth)) << (8 - depth)
    image = Image.fromarray(img_array)

    return image


def validate_image(file_stream, max_size_bytes=10 * 1024 * 1024) -> Image.Image:
    """
    Validate uploaded image to prevent malformed or oversized inputs.
    """
    raw_bytes = file_stream.read()

    if len(raw_bytes) == 0:
        raise ValueError("Empty file uploaded")

    if len(raw_bytes) > max_size_bytes:
        raise ValueError(f"File too large. Maximum size is {max_size_bytes} bytes")

    try:
        image = Image.open(io.BytesIO(raw_bytes))
        image.verify()
        # Re-open after verify (verify can consume the stream)
        image = Image.open(io.BytesIO(raw_bytes))
    except Exception as e:
        raise ValueError(f"Invalid image file: {str(e)}")

    # Restrict to common image formats
    if image.format and image.format.upper() not in ('JPEG', 'JPG', 'PNG', 'BMP', 'WEBP'):
        raise ValueError(f"Unsupported image format: {image.format}")

    # Restrict image dimensions to prevent resource exhaustion
    max_dimension = 4096
    if image.width > max_dimension or image.height > max_dimension:
        raise ValueError(f"Image dimensions too large. Max {max_dimension}x{max_dimension}")

    # Convert to RGB (handles RGBA, grayscale, etc.)
    image = image.convert('RGB')

    return image


def compute_confidence_threshold(probabilities: torch.Tensor) -> dict:
    """
    Apply confidence thresholding to flag potentially adversarial inputs.
    Adversarial examples often produce unusual probability distributions.
    """
    top_prob = probabilities.max().item()
    entropy = -(probabilities * torch.log(probabilities + 1e-10)).sum().item()

    # High entropy or very low confidence may indicate adversarial input
    is_suspicious = entropy > 5.0 or top_prob < 0.1

    return {
        "entropy": round(entropy, 4),
        "is_suspicious": is_suspicious
    }


@app.route('/predict', methods=['POST'])
def predict():
    if 'image' not in request.files:
        return jsonify({"error": "No image file provided. Use 'image' field."}), 400

    file = request.files['image']

    # Validate the uploaded image
    try:
        image = validate_image(file)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    # Apply adversarial defenses (input transformations)
    image = apply_input_defenses(image)

    # Apply standard preprocessing
    input_tensor = STANDARD_TRANSFORM(image).unsqueeze(0)

    # Clamp input to expected range after normalization as additional safety
    # For ImageNet normalization, valid pixel range maps approximately to [-2.2, 2.7]
    input_tensor = torch.clamp(input_tensor, min=-3.0, max=3.0)

    # Run inference with no gradient computation
    with torch.no_grad():
        outputs = model(input_tensor)
        probabilities = torch.nn.functional.softmax(outputs[0], dim=0)

    # Get top-5 predictions
    top5_prob, top5_catid = torch.topk(probabilities, 5)

    # Check for adversarial indicators
    adversarial_check = compute_confidence_threshold(probabilities)

    # Build response
    top_class_idx = top5_catid[0].item()
    top_confidence = top5_prob[0].item()

    predictions = []
    for i in range(5):
        idx = top5_catid[i].item()
        predictions.append({
            "class": categories[idx] if idx < len(categories) else f"class_{idx}",
            "confidence": round(top5_prob[i].item(), 4)
        })

    response = {
        "predicted_class": categories[top_class_idx] if top_class_idx < len(categories) else f"class_{top_class_idx}",
        "confidence": round(top_confidence, 4),
        "top5_predictions": predictions,
        "adversarial_analysis": adversarial_check,
    }

    # If input is flagged as suspicious, add a warning for the content moderation system
    if adversarial_check["is_suspicious"]:
        response["warning"] = (
            "This input has been flagged as potentially adversarial. "
            "The prediction may be unreliable. Manual review recommended."
        )
        response["moderation_action"] = "FLAG_FOR_REVIEW"

    return jsonify(response)


